import type { CommentStyle } from "../../lib/marker.ts";

/**
 * A bundled asset (agent, skill, hook) parsed into its three zones:
 *
 *   frontmatter ─ YAML key:value pairs at the top of the file.
 *   managedBody ─ navori-base content, regenerated by sync.
 *   userTemplate ─ optional template for the user-section, written only on
 *                  first render of the destination file.
 *
 * The split is anchored by a sentinel that depends on the comment style:
 *   - html (markdown): `<!-- navori:user-section -->`
 *   - shell:           `# navori:user-section` (whole line)
 *
 * Assets without a sentinel are valid — userTemplate becomes null and the
 * whole post-frontmatter chunk is managedBody.
 */

const SENTINEL_BY_STYLE: Record<CommentStyle, string> = {
  html: "<!-- navori:user-section -->",
  shell: "# navori:user-section",
};

export class AssetParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "AssetParseError";
  }
}

export interface ParsedAsset {
  frontmatter: Record<string, string>;
  managedBody: string;
  userTemplate: string | null;
  commentStyle: CommentStyle;
}

export function parseAsset(raw: string, commentStyle: CommentStyle): ParsedAsset {
  const fmMatch = raw.match(/^---\n([\s\S]*?)\n---\n([\s\S]*)$/);
  if (!fmMatch) {
    throw new AssetParseError(
      "asset must start with a YAML frontmatter block delimited by `---` lines",
    );
  }

  const frontmatter: Record<string, string> = {};
  for (const line of fmMatch[1].split("\n")) {
    const kv = line.match(/^([a-zA-Z_][a-zA-Z0-9_]*):\s*(.*)$/);
    if (kv) frontmatter[kv[1]] = kv[2].trim();
  }

  const sentinel = SENTINEL_BY_STYLE[commentStyle];
  const afterFm = fmMatch[2];
  const sentinelIdx = findSentinel(afterFm, sentinel, commentStyle);

  if (sentinelIdx < 0) {
    return {
      frontmatter,
      managedBody: afterFm.trim(),
      userTemplate: null,
      commentStyle,
    };
  }

  const managedBody = afterFm.slice(0, sentinelIdx).trim();
  // Skip the sentinel itself + its trailing newline if present
  const tail = afterFm.slice(sentinelIdx + sentinel.length);
  const userTemplate = tail.replace(/^\n/, "");
  return { frontmatter, managedBody, userTemplate, commentStyle };
}

function findSentinel(haystack: string, sentinel: string, style: CommentStyle): number {
  if (style === "shell") {
    // Shell sentinel must occupy a whole line so it can't collide with a
    // user comment that happens to contain "navori:user-section" inline.
    const escaped = sentinel.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const re = new RegExp(`^${escaped}$`, "m");
    const m = re.exec(haystack);
    return m ? m.index : -1;
  }
  return haystack.indexOf(sentinel);
}
